{
  "summary": "This paper introduces Continual Knowledge Learning (CKL), a novel continual learning formulation aimed at updating the internal world knowledge of large language models through continual pretraining on new corpora. It proposes a new benchmark with datasets probing invariant, updated, and new knowledge, alongside a novel FUAR metric to evaluate forgetting and acquisition trade-offs, and evaluates several adapted continual learning methods, finding parameter-expansion approaches most effective but highlighting challenges in multi-phase updates and memory efficiency.",
  "strengths": [
    {
      "point": "Novel problem formulation targeting continual updating of LM knowledge",
      "evidence": "The paper clearly defines CKL as distinct from traditional continual learning and formulates the problem of balancing retention, updating, and acquisition of knowledge."
    },
    {
      "point": "Comprehensive benchmark construction with multiple datasets",
      "evidence": "The benchmark includes Invariant LAMA, Updated LAMA, New LAMA, and New LAMA-EASY datasets, designed to probe different aspects of knowledge retention and acquisition."
    },
    {
      "point": "Introduction of a novel evaluation metric (FUAR)",
      "evidence": "FUAR measures the ratio of forgotten knowledge to updated plus acquired knowledge, providing a quantitative way to assess the trade-off between forgetting and learning."
    },
    {
      "point": "Extensive empirical evaluation of multiple continual learning paradigms",
      "evidence": "The paper adapts and compares regularization, rehearsal, and parameter-expansion methods on the CKL benchmark, revealing parameter-expansion methods as most effective."
    },
    {
      "point": "Insightful analysis of multi-phase continual learning challenges",
      "evidence": "Experiments show that multiple update phases increase forgetting and degrade performance, highlighting scalability issues."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to related knowledge editing and model patching literature",
      "evidence": "The paper omits discussion and empirical baselines from knowledge editing methods like ROME or MEMIT, missing an opportunity to position CKL relative to these approaches."
    },
    {
      "point": "Insufficient transparency and justification in benchmark dataset construction",
      "evidence": "The criteria for classifying facts as invariant or outdated and the rationale behind difficulty stratification in New LAMA datasets are not clearly explained."
    },
    {
      "point": "No ablation or sensitivity analysis of the FUAR metric",
      "evidence": "The paper does not explore how varying the weighting of forgetting versus acquisition affects rankings or provide alternative metric formulations."
    },
    {
      "point": "Incomplete details and tuning of rehearsal baseline (Mix-Review)",
      "evidence": "Critical hyperparameters like rehearsal buffer size and sampling strategy are missing, raising concerns that poor rehearsal performance may stem from suboptimal implementation."
    },
    {
      "point": "Reproducibility hindered by missing critical training and model details",
      "evidence": "Key hyperparameters, learning rate schedules, model sizes, tokenizer versions, and checkpoint modifications are not specified."
    },
    {
      "point": "Ambiguous definition and scope of 'invariant knowledge'",
      "evidence": "The paper does not precisely define invariant knowledge, complicating interpretation of forgetting results."
    },
    {
      "point": "Limited downstream evaluation beyond KILT fine-tuning",
      "evidence": "No zero-shot or few-shot evaluations on other knowledge-intensive tasks or domains are provided."
    },
    {
      "point": "No analysis of computational cost or memory overhead",
      "evidence": "Parameter-expansion methods' memory inefficiency is noted but not quantified or visualized."
    },
    {
      "point": "No discussion or solutions for multi-phase CKL scalability and conflicting knowledge",
      "evidence": "The paper identifies forgetting increase over multiple updates but does not propose mitigation strategies or address contradictory knowledge scenarios."
    },
    {
      "point": "Narrow evaluation scope limited to English news domain and medium-sized models",
      "evidence": "No cross-lingual, cross-domain, or large-scale model experiments are conducted."
    },
    {
      "point": "Absence of qualitative or human evaluation of knowledge updates",
      "evidence": "Evaluation relies solely on automatic metrics without error analysis or human judgments."
    },
    {
      "point": "Limited exploration of alternative continual learning paradigms",
      "evidence": "Other promising approaches like meta-learning, prompt-based adaptation, or retrieval-augmentation are not considered."
    },
    {
      "point": "No discussion of ethical or safety implications",
      "evidence": "Potential risks of incorporating incorrect or biased knowledge during continual updates are not addressed."
    }
  ],
  "questions": [
    {
      "question": "How does CKL compare empirically and conceptually to knowledge editing and model patching methods?",
      "motivation": "Understanding this would clarify CKL's novelty and practical advantages over existing knowledge update techniques."
    },
    {
      "question": "How robust and fair is the FUAR metric across different weighting schemes and knowledge types?",
      "motivation": "Validating FUAR's sensitivity is important to ensure reliable evaluation and method comparison."
    },
    {
      "question": "Can the benchmark datasets be better characterized with clear annotation protocols and statistical properties?",
      "motivation": "This would increase confidence in the benchmark's validity and facilitate reproducibility."
    },
    {
      "question": "What are the computational and memory costs of CKL methods, especially parameter-expansion approaches, in realistic deployment scenarios?",
      "motivation": "Assessing efficiency is critical for practical adoption of continual knowledge updating."
    },
    {
      "question": "How do CKL methods perform on larger models, diverse languages, and domains beyond English news?",
      "motivation": "Evaluating generalizability is necessary to establish broad applicability."
    },
    {
      "question": "Are there effective strategies to mitigate forgetting and memory growth in multi-phase continual knowledge updates?",
      "motivation": "Addressing scalability challenges is essential for real-world continual updating."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
